import React, { useState, useEffect } from 'react';
import {
  Box,
  Card,
  CardContent,
  Grid,
  Typography,
  IconButton,
  Stack,
  CircularProgress,
  LinearProgress,
  Chip,
  Switch,
  FormControlLabel,
  useTheme,
  Button,
} from '@mui/material';
import {
  Memory as MemoryIcon,
  Storage as StorageIcon,
  Speed as SpeedIcon,
  CloudSync as CloudSyncIcon,
  DnsOutlined as DnsIcon,
  PowerSettingsNew as PowerIcon,
  Refresh as RefreshIcon,
  OpenInNew as OpenInNewIcon,
  LightMode as LightModeIcon,
  DarkMode as DarkModeIcon,
} from '@mui/icons-material';
import { getSystemInfo, getSystemStatus, startService, stopService } from '../services/api';
import { getCommonStyles } from '../styles/commonStyles';

const Dashboard = ({ mode, setMode, onDashboardClick = () => {} }) => {
  const theme = useTheme();
  const styles = getCommonStyles(theme);
  const [loading, setLoading] = useState(false);
  const [systemInfo, setSystemInfo] = useState({
    hostname: '',
    platform: '',
    arch: '',
    uptime: 0,
    cpu_usage: 0,
    memory_total: 0,
    memory_used: 0,
  });
  const [serviceStatus, setServiceStatus] = useState({
    singbox: {
      running: false,
      version: '',
    },
    mosdns: {
      running: false,
      version: '',
    },
  });
  const [subscriptionInfo, setSubscriptionInfo] = useState({
    url: '',
    last_update: '',
    next_update: '',
    node_count: 0,
    active_nodes: 0,
  });

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 5000); // 每5秒更新一次
    return () => clearInterval(interval);
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      const [sysInfo, sysStatus] = await Promise.all([
        getSystemInfo(),
        getSystemStatus(),
      ]);

      // 更新系统信息
      setSystemInfo({
        hostname: sysInfo.hostname || '',
        platform: sysInfo.platform || '',
        arch: sysInfo.arch || '',
        uptime: sysInfo.uptime || 0,
        cpu_usage: sysInfo.cpu_usage || 0,
        memory_total: sysInfo.memory_total || 0,
        memory_used: sysInfo.memory_used || 0,
      });

      // 更新服务状态
      setServiceStatus({
        singbox: {
          running: sysStatus.services?.singbox || false,
          version: sysStatus.versions?.singbox || '',
        },
        mosdns: {
          running: sysStatus.services?.mosdns || false,
          version: sysStatus.versions?.mosdns || '',
        },
      });

      // 更新订阅信息
      if (sysStatus.subscriptions?.length > 0) {
        const sub = sysStatus.subscriptions[0];
        setSubscriptionInfo({
          url: sub.url || '',
          last_update: sub.last_update || '',
          next_update: sub.next_update || '',
          node_count: sub.node_count || 0,
          active_nodes: sub.active_nodes || 0,
        });
      }
    } catch (error) {
      console.error('Failed to fetch data:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleServiceToggle = async (service, status) => {
    try {
      setLoading(true);
      if (status) {
        await stopService(service);
      } else {
        await startService(service);
      }
      await fetchData();
    } catch (error) {
      console.error(`Failed to toggle ${service}:`, error);
    } finally {
      setLoading(false);
    }
  };

  const formatBytes = (bytes) => {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return `${parseFloat((bytes / Math.pow(k, i)).toFixed(2))} ${sizes[i]}`;
  };

  const formatUptime = (seconds) => {
    const days = Math.floor(seconds / (24 * 60 * 60));
    const hours = Math.floor((seconds % (24 * 60 * 60)) / (60 * 60));
    const minutes = Math.floor((seconds % (60 * 60)) / 60);
    return `${days}天 ${hours}小时 ${minutes}分钟`;
  };

  const formatDate = (dateString) => {
    if (!dateString) return '-';
    const date = new Date(dateString);
    return date.toLocaleString('zh-CN', {
      year: 'numeric',
      month: '2-digit',
      day: '2-digit',
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
    });
  };

  return (
    <Box>
      <Card sx={styles.headerCard}>
        <CardContent sx={{ py: 1.5, px: 2, '&:last-child': { pb: 1.5 } }}>
          <Stack direction="row" alignItems="center" justifyContent="space-between">
            <Stack direction="row" alignItems="center" spacing={2}>
              <Typography variant="h5" sx={{ fontWeight: 500, color: 'inherit' }}>
                仪表盘
              </Typography>
              {loading && (
                <Box sx={{ display: 'flex', alignItems: 'center' }}>
                  <CircularProgress size={20} thickness={4} sx={{ color: 'rgba(255,255,255,0.8)' }} />
                </Box>
              )}
            </Stack>
            <Stack direction="row" spacing={1}>
              {onDashboardClick && (
                <IconButton
                  size="small"
                  onClick={onDashboardClick}
                  sx={styles.iconButton}
                >
                  <OpenInNewIcon fontSize="small" />
                </IconButton>
              )}
              <IconButton
                size="small"
                onClick={() => setMode(mode === 'dark' ? 'light' : 'dark')}
                sx={styles.iconButton}
              >
                {mode === 'dark' ? <LightModeIcon fontSize="small" /> : <DarkModeIcon fontSize="small" />}
              </IconButton>
            </Stack>
          </Stack>
        </CardContent>
      </Card>

      {loading && <LinearProgress sx={{ mb: 1 }} />}

      {/* First Row: System Information */}
      <Grid container spacing={1.5} sx={{ mb: 1.5 }}>
        {/* System Info */}
        <Grid item xs={12} md={3}>
          <Card sx={styles.card}>
            <CardContent>
              <Stack spacing={2}>
                <Stack direction="row" alignItems="center" spacing={1}>
                  <StorageIcon color="primary" />
                  <Typography variant="h6">系统信息</Typography>
                </Stack>
                <Stack spacing={1}>
                  <Typography variant="body2">
                    主机名：{systemInfo.hostname}
                  </Typography>
                  <Typography variant="body2">
                    架构：{systemInfo.arch}
                  </Typography>
                  <Typography variant="body2">
                    运行时间：{formatUptime(systemInfo.uptime)}
                  </Typography>
                </Stack>
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        {/* CPU Usage */}
        <Grid item xs={12} md={3}>
          <Card sx={styles.card}>
            <CardContent>
              <Stack spacing={2}>
                <Stack direction="row" alignItems="center" spacing={1}>
                  <SpeedIcon color="primary" />
                  <Typography variant="h6">CPU 使用率</Typography>
                </Stack>
                <Box sx={{ position: 'relative', display: 'inline-flex', width: '100%', justifyContent: 'center' }}>
                  <CircularProgress
                    variant="determinate"
                    value={systemInfo.cpu_usage}
                    size={100}
                    thickness={4}
                    sx={{
                      color: theme.palette.mode === 'dark' ? 'primary.light' : 'primary.main',
                    }}
                  />
                  <Box
                    sx={{
                      top: 0,
                      left: 0,
                      bottom: 0,
                      right: 0,
                      position: 'absolute',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                    }}
                  >
                    <Typography variant="h5" component="div" color="text.secondary">
                      {`${Math.round(systemInfo.cpu_usage)}%`}
                    </Typography>
                  </Box>
                </Box>
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        {/* Memory Usage */}
        <Grid item xs={12} md={3}>
          <Card sx={styles.card}>
            <CardContent>
              <Stack spacing={2}>
                <Stack direction="row" alignItems="center" spacing={1}>
                  <MemoryIcon color="primary" />
                  <Typography variant="h6">内存使用率</Typography>
                </Stack>
                <Box sx={{ position: 'relative', display: 'inline-flex', width: '100%', justifyContent: 'center' }}>
                  <CircularProgress
                    variant="determinate"
                    value={(systemInfo.memory_used / systemInfo.memory_total) * 100}
                    size={100}
                    thickness={4}
                    sx={{
                      color: theme.palette.mode === 'dark' ? 'primary.light' : 'primary.main',
                    }}
                  />
                  <Box
                    sx={{
                      top: 0,
                      left: 0,
                      bottom: 0,
                      right: 0,
                      position: 'absolute',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                    }}
                  >
                    <Typography variant="h5" component="div" color="text.secondary">
                      {`${Math.round((systemInfo.memory_used / systemInfo.memory_total) * 100)}%`}
                    </Typography>
                  </Box>
                </Box>
                <Typography variant="body2" color="text.secondary" align="center">
                  {`${formatBytes(systemInfo.memory_used)} / ${formatBytes(systemInfo.memory_total)}`}
                </Typography>
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        {/* Network Status */}
        <Grid item xs={12} md={3}>
          <Card sx={styles.card}>
            <CardContent>
              <Stack spacing={2}>
                <Stack direction="row" alignItems="center" spacing={1}>
                  <CloudSyncIcon color="primary" />
                  <Typography variant="h6">网络状态</Typography>
                  <Chip 
                    label="在线"
                    size="small"
                    sx={{
                      ...styles.chip.success,
                      background: 'linear-gradient(45deg, #4caf50 30%, #81c784 90%)',
                      color: '#fff',
                      fontWeight: 500,
                    }}
                  />
                </Stack>
                <Stack spacing={1}>
                  <Box>
                    <Typography variant="body2" color="text.secondary" gutterBottom>
                      上行速率
                    </Typography>
                    <Typography variant="h6" sx={{ color: theme.palette.success.main }}>
                      {formatBytes(0)}/s
                    </Typography>
                  </Box>
                  <Box>
                    <Typography variant="body2" color="text.secondary" gutterBottom>
                      下行速率
                    </Typography>
                    <Typography variant="h6" sx={{ color: theme.palette.primary.main }}>
                      {formatBytes(0)}/s
                    </Typography>
                  </Box>
                </Stack>
              </Stack>
            </CardContent>
          </Card>
        </Grid>
      </Grid>

      {/* Second Row: Service Status and Subscriptions */}
      <Grid container spacing={1.5}>
        {/* Singbox Status */}
        <Grid item xs={12} md={3}>
          <Card sx={styles.card}>
            <CardContent>
              <Stack spacing={2}>
                <Stack direction="row" alignItems="center" spacing={1}>
                  <PowerIcon color="primary" />
                  <Typography variant="h6">Singbox 状态</Typography>
                  <Chip 
                    label={serviceStatus.singbox.running ? "运行中" : "已停止"}
                    size="small"
                    sx={{
                      ...serviceStatus.singbox.running ? styles.chip.success : styles.chip.error,
                      background: serviceStatus.singbox.running 
                        ? 'linear-gradient(45deg, #4caf50 30%, #81c784 90%)'
                        : 'linear-gradient(45deg, #f44336 30%, #e57373 90%)',
                      color: '#fff',
                      fontWeight: 500,
                    }}
                  />
                </Stack>
                <Stack spacing={1}>
                  <Stack direction="row" justifyContent="space-between" alignItems="center">
                    <Typography variant="body2">版本</Typography>
                    <Typography variant="body2">{serviceStatus.singbox.version || '-'}</Typography>
                  </Stack>
                </Stack>
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        {/* Mosdns Status */}
        <Grid item xs={12} md={3}>
          <Card sx={styles.card}>
            <CardContent>
              <Stack spacing={2}>
                <Stack direction="row" alignItems="center" spacing={1}>
                  <DnsIcon color="primary" />
                  <Typography variant="h6">Mosdns 状态</Typography>
                  <Chip 
                    label={serviceStatus.mosdns.running ? "运行中" : "已停止"}
                    size="small"
                    sx={{
                      ...serviceStatus.mosdns.running ? styles.chip.success : styles.chip.error,
                      background: serviceStatus.mosdns.running 
                        ? 'linear-gradient(45deg, #4caf50 30%, #81c784 90%)'
                        : 'linear-gradient(45deg, #f44336 30%, #e57373 90%)',
                      color: '#fff',
                      fontWeight: 500,
                    }}
                  />
                </Stack>
                <Stack spacing={1}>
                  <Stack direction="row" justifyContent="space-between" alignItems="center">
                    <Typography variant="body2">版本</Typography>
                    <Typography variant="body2">{serviceStatus.mosdns.version || '-'}</Typography>
                  </Stack>
                </Stack>
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        {/* Service Control */}
        <Grid item xs={12} md={3}>
          <Card sx={styles.card}>
            <CardContent>
              <Stack spacing={2}>
                <Stack direction="row" alignItems="center" spacing={1}>
                  <PowerIcon color="primary" />
                  <Typography variant="h6">服务控制</Typography>
                </Stack>
                <Stack spacing={2}>
                  <Box>
                    <Typography variant="body2" color="text.secondary" gutterBottom>
                      Singbox 服务
                    </Typography>
                    <Stack direction="row" spacing={1}>
                      <Button
                        variant="contained"
                        size="small"
                        disabled={loading || serviceStatus.singbox.running}
                        onClick={() => handleServiceToggle('singbox', false)}
                        sx={{
                          flex: 1,
                          background: 'linear-gradient(45deg, #4caf50 30%, #81c784 90%)',
                          color: '#fff',
                          '&:disabled': {
                            background: 'linear-gradient(45deg, rgba(76, 175, 80, 0.5) 30%, rgba(129, 199, 132, 0.5) 90%)',
                            color: 'rgba(255, 255, 255, 0.5)',
                          },
                        }}
                      >
                        启动
                      </Button>
                      <Button
                        variant="contained"
                        size="small"
                        disabled={loading || !serviceStatus.singbox.running}
                        onClick={() => handleServiceToggle('singbox', true)}
                        sx={{
                          flex: 1,
                          background: 'linear-gradient(45deg, #f44336 30%, #e57373 90%)',
                          color: '#fff',
                          '&:disabled': {
                            background: 'linear-gradient(45deg, rgba(244, 67, 54, 0.5) 30%, rgba(229, 115, 115, 0.5) 90%)',
                            color: 'rgba(255, 255, 255, 0.5)',
                          },
                        }}
                      >
                        停止
                      </Button>
                    </Stack>
                  </Box>
                  <Box>
                    <Typography variant="body2" color="text.secondary" gutterBottom>
                      Mosdns 服务
                    </Typography>
                    <Stack direction="row" spacing={1}>
                      <Button
                        variant="contained"
                        size="small"
                        disabled={loading || serviceStatus.mosdns.running}
                        onClick={() => handleServiceToggle('mosdns', false)}
                        sx={{
                          flex: 1,
                          background: 'linear-gradient(45deg, #4caf50 30%, #81c784 90%)',
                          color: '#fff',
                          '&:disabled': {
                            background: 'linear-gradient(45deg, rgba(76, 175, 80, 0.5) 30%, rgba(129, 199, 132, 0.5) 90%)',
                            color: 'rgba(255, 255, 255, 0.5)',
                          },
                        }}
                      >
                        启动
                      </Button>
                      <Button
                        variant="contained"
                        size="small"
                        disabled={loading || !serviceStatus.mosdns.running}
                        onClick={() => handleServiceToggle('mosdns', true)}
                        sx={{
                          flex: 1,
                          background: 'linear-gradient(45deg, #f44336 30%, #e57373 90%)',
                          color: '#fff',
                          '&:disabled': {
                            background: 'linear-gradient(45deg, rgba(244, 67, 54, 0.5) 30%, rgba(229, 115, 115, 0.5) 90%)',
                            color: 'rgba(255, 255, 255, 0.5)',
                          },
                        }}
                      >
                        停止
                      </Button>
                    </Stack>
                  </Box>
                </Stack>
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        {/* Subscription Info */}
        <Grid item xs={12} md={3}>
          <Card sx={styles.card}>
            <CardContent>
              <Stack spacing={2}>
                <Stack direction="row" alignItems="center" spacing={1}>
                  <CloudSyncIcon color="primary" />
                  <Typography variant="h6">订阅信息</Typography>
                  <Chip 
                    label={subscriptionInfo.active_nodes > 0 ? "活跃" : "未激活"}
                    size="small"
                    sx={{
                      ...subscriptionInfo.active_nodes > 0 ? styles.chip.success : styles.chip.error,
                      background: subscriptionInfo.active_nodes > 0
                        ? 'linear-gradient(45deg, #4caf50 30%, #81c784 90%)'
                        : 'linear-gradient(45deg, #f44336 30%, #e57373 90%)',
                      color: '#fff',
                      fontWeight: 500,
                    }}
                  />
                </Stack>
                <Stack spacing={1}>
                  <Box>
                    <Typography variant="body2" color="text.secondary" gutterBottom>
                      节点数量
                    </Typography>
                    <Typography variant="body1">
                      {subscriptionInfo.active_nodes} / {subscriptionInfo.node_count}
                    </Typography>
                  </Box>
                  <Box>
                    <Typography variant="body2" color="text.secondary" gutterBottom>
                      上次更新
                    </Typography>
                    <Typography variant="body1">
                      {formatDate(subscriptionInfo.last_update)}
                    </Typography>
                  </Box>
                  <Box>
                    <Typography variant="body2" color="text.secondary" gutterBottom>
                      下次更新
                    </Typography>
                    <Typography variant="body1">
                      {formatDate(subscriptionInfo.next_update)}
                    </Typography>
                  </Box>
                </Stack>
              </Stack>
            </CardContent>
          </Card>
        </Grid>
      </Grid>
    </Box>
  );
};

export default Dashboard;
